import type { Field, Model } from '@prisma/dmmf'

const PRISMA_TO_TS_TYPE: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'bigint',
  DateTime: 'Date | string',
  Json: 'unknown',
  Bytes: 'Buffer',
}

/** Map a Prisma scalar type name to its TypeScript equivalent. */
export function mapScalarType(prismaType: string): string {
  return PRISMA_TO_TS_TYPE[prismaType] ?? 'unknown'
}

/** Produce the TypeScript type string for a single DMMF field. */
export function fieldToTsType(field: Field): string {
  let tsType: string

  switch (field.kind) {
    case 'scalar':
      tsType = mapScalarType(field.type)
      break
    case 'enum':
      tsType = field.type
      break
    case 'object':
      tsType = field.type
      break
    default:
      tsType = 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  } else if (!field.isRequired) {
    tsType = `${tsType} | null`
  }

  return tsType
}

/** Build an interface declaration for a model. */
export function generateModelInterface(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => `  ${f.name}: ${fieldToTsType(f)}`)
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/**
 * Build an input type for creating a model.
 * Omits auto-generated fields (id with default, createdAt, updatedAt).
 */
export function generateCreateInput(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .filter((f) => !f.isGenerated && !f.isUpdatedAt)
    .map((f) => {
      const optional = f.hasDefaultValue || !f.isRequired
      const separator = optional ? '?:' : ':'
      return `  ${f.name}${separator} ${fieldToTsType(f)}`
    })
    .join('\n')

  return `export interface ${model.name}CreateInput {\n${fields}\n}`
}

/**
 * Build an input type for updating a model.
 * All fields are optional since partial updates are the norm.
 */
export function generateUpdateInput(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .filter((f) => !f.isReadOnly && !f.isGenerated)
    .map((f) => `  ${f.name}?: ${fieldToTsType(f)}`)
    .join('\n')

  return `export interface ${model.name}UpdateInput {\n${fields}\n}`
}

/** Build a `WhereUniqueInput` type from the model's unique/id fields. */
export function generateWhereUniqueInput(model: Model): string {
  const uniqueFields = model.fields.filter((f) => f.isId || f.isUnique)

  const fields = uniqueFields.map((f) => `  ${f.name}?: ${fieldToTsType(f)}`).join('\n')

  return `export interface ${model.name}WhereUniqueInput {\n${fields}\n}`
}

/** Convert a model name to a lowercase REST resource path segment. */
export function toResourcePath(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1)
}

/** Generate the CRUD methods for a single model. */
export function generateModelMethods(model: Model): string {
  const name = model.name
  const resource = toResourcePath(name)

  return `  ${resource} = {
    findMany: (params?: RequestInit): Promise<${name}[]> => {
      return this.request<${name}[]>(\`/\${this.baseUrl}/${resource}\`, {
        method: 'GET',
        ...params,
      })
    },

    findUnique: (where: ${name}WhereUniqueInput, params?: RequestInit): Promise<${name} | null> => {
      const query = new URLSearchParams(
        Object.entries(where).reduce<Record<string, string>>((acc, [k, v]) => {
          if (v !== undefined) acc[k] = String(v)
          return acc
        }, {}),
      ).toString()
      return this.request<${name} | null>(\`/\${this.baseUrl}/${resource}?\${query}\`, {
        method: 'GET',
        ...params,
      })
    },

    create: (data: ${name}CreateInput, params?: RequestInit): Promise<${name}> => {
      return this.request<${name}>(\`/\${this.baseUrl}/${resource}\`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
        ...params,
      })
    },

    update: (where: ${name}WhereUniqueInput, data: ${name}UpdateInput, params?: RequestInit): Promise<${name}> => {
      const query = new URLSearchParams(
        Object.entries(where).reduce<Record<string, string>>((acc, [k, v]) => {
          if (v !== undefined) acc[k] = String(v)
          return acc
        }, {}),
      ).toString()
      return this.request<${name}>(\`/\${this.baseUrl}/${resource}?\${query}\`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
        ...params,
      })
    },

    delete: (where: ${name}WhereUniqueInput, params?: RequestInit): Promise<${name}> => {
      const query = new URLSearchParams(
        Object.entries(where).reduce<Record<string, string>>((acc, [k, v]) => {
          if (v !== undefined) acc[k] = String(v)
          return acc
        }, {}),
      ).toString()
      return this.request<${name}>(\`/\${this.baseUrl}/${resource}?\${query}\`, {
        method: 'DELETE',
        ...params,
      })
    },
  }`
}

/** Generate the full `rest-client.ts` file content from a list of models and enums. */
export function generateRestClient(models: readonly Model[], enums: readonly { name: string; values: readonly { name: string }[] }[]): string {
  const sections: string[] = []

  sections.push(fileHeader())

  for (const enumDef of enums) {
    sections.push(generateEnum(enumDef))
  }

  for (const model of models) {
    sections.push(generateModelInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
    sections.push(generateWhereUniqueInput(model))
  }

  sections.push(generateClientClass(models))

  return sections.join('\n\n') + '\n'
}

function fileHeader(): string {
  return `// This file was auto-generated by prisma-generator-rest-client. Do not edit manually.
/* eslint-disable */`
}

function generateEnum(enumDef: { name: string; values: readonly { name: string }[] }): string {
  const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')

  return `export enum ${enumDef.name} {\n${members}\n}`
}

function generateClientClass(models: readonly Model[]): string {
  const modelMethods = models.map(generateModelMethods).join('\n\n')

  return `export class RestApiClient {
  #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl.replace(/\\/+$/, '')
  }

  get baseUrl(): string {
    return this.#baseUrl
  }

  private async request<T>(url: string, init: RequestInit): Promise<T> {
    const response = await fetch(url, init)
    if (!response.ok) {
      throw new Error(\`REST API error: \${response.status} \${response.statusText}\`)
    }
    return response.json() as Promise<T>
  }

${modelMethods}
}`
}

