import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './template'

/** Main generation logic invoked by the generator handler. */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('No output directory specified for generator-rest-client. Please set the `output` option in your schema.')
  }

  const models = options.dmmf.datamodel.models
  const enums = options.dmmf.datamodel.enums

  const code = generateRestClient(models, enums)

  await fs.promises.mkdir(outputDir, { recursive: true })
  await fs.promises.writeFile(path.join(outputDir, 'rest-client.ts'), code, 'utf-8')
}

