import { describe, expect, test } from 'vitest'

import type { Field, Model } from '@prisma/dmmf'

import {
  fieldToTsType,
  generateCreateInput,
  generateModelInterface,
  generateRestClient,
  generateUpdateInput,
  generateWhereUniqueInput,
  mapScalarType,
  toResourcePath,
} from '../template'

const scalarField = (overrides: Partial<Field> = {}): Field =>
  ({
    kind: 'scalar',
    name: 'name',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  }) as unknown as Field

const userModel: Model = {
  name: 'User',
  dbName: null,
  schema: null,
  fields: [
    scalarField({ name: 'id', type: 'Int', isId: true, isUnique: true, hasDefaultValue: true }),
    scalarField({ name: 'email', type: 'String', isUnique: true }),
    scalarField({ name: 'name', type: 'String', isRequired: false }),
    scalarField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
    scalarField({ name: 'updatedAt', type: 'DateTime', isUpdatedAt: true }),
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
} as unknown as Model

describe('mapScalarType', () => {
  test('maps known Prisma scalar types to TypeScript types', () => {
    expect(mapScalarType('String')).toBe('string')
    expect(mapScalarType('Int')).toBe('number')
    expect(mapScalarType('Float')).toBe('number')
    expect(mapScalarType('Boolean')).toBe('boolean')
    expect(mapScalarType('DateTime')).toBe('Date | string')
    expect(mapScalarType('BigInt')).toBe('bigint')
    expect(mapScalarType('Json')).toBe('unknown')
    expect(mapScalarType('Bytes')).toBe('Buffer')
    expect(mapScalarType('Decimal')).toBe('number')
  })

  test('returns unknown for unrecognized types', () => {
    expect(mapScalarType('CustomType')).toBe('unknown')
  })
})

describe('fieldToTsType', () => {
  test('handles required scalar', () => {
