  ({
    kind: 'scalar',
    name: 'name',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  }) as unknown as Field

