import fs from 'node:fs'
import os from 'node:os'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'
import { afterEach, beforeEach, describe, expect, test } from 'vitest'

import { generate } from '../generator'

function makeDmmf(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: {
      models,
      enums,
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

function makeOptions(outputDir: string, dmmf: DMMF.Document): GeneratorOptions {
  return {
    generator: {
      name: 'restClient',
      output: { fromEnvVar: null, value: outputDir },
      provider: { fromEnvVar: null, value: 'prisma-generator-rest-client' },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/tmp/schema.prisma',
    },
    otherGenerators: [],
    schemaPath: '/tmp/schema.prisma',
    dmmf,
    datasources: [],
    datamodel: '',
    version: 'test',
  }
}

describe('generate', () => {
  let tmpDir: string

  beforeEach(async () => {
    tmpDir = await fs.promises.mkdtemp(path.join(os.tmpdir(), 'gen-rest-'))
  })

  afterEach(async () => {
    await fs.promises.rm(tmpDir, { recursive: true, force: true })
  })

  test('writes rest-client.ts to the output directory', async () => {
    const outputDir = path.join(tmpDir, 'generated')
    const dmmf = makeDmmf([
      {
        name: 'User',
        dbName: null,
        schema: null,
        fields: [
          {
            kind: 'scalar',
            name: 'id',
            isRequired: true,
            isList: false,
            isUnique: true,
            isId: true,
            isReadOnly: false,
            type: 'Int',
            hasDefaultValue: true,
            default: { name: 'autoincrement', args: [] },
          },
          {
            kind: 'scalar',
            name: 'email',
            isRequired: true,
            isList: false,
            isUnique: true,
            isId: false,
            isReadOnly: false,
            type: 'String',
            hasDefaultValue: false,
          },
        ],
        uniqueFields: [],
        uniqueIndexes: [],
        primaryKey: null,
      },
    ])

    const options = makeOptions(outputDir, dmmf)
    await generate(options)

    const filePath = path.join(outputDir, 'rest-client.ts')
    expect(fs.existsSync(filePath)).toBe(true)

    const content = await fs.promises.readFile(filePath, 'utf-8')
    expect(content).toContain('export interface User {')
    expect(content).toContain('export class RestApiClient {')
    expect(content).toContain('findMany')
    expect(content).toContain('findUnique')
    expect(content).toContain('create')
    expect(content).toContain('update')
    expect(content).toContain('delete')
  })

  test('throws when no output is specified', async () => {
    const dmmf = makeDmmf([])
    const options = makeOptions(tmpDir, dmmf)
    options.generator.output = null

    await expect(generate(options)).rejects.toThrow('No output directory specified')
  })

  test('generates enums', async () => {
    const outputDir = path.join(tmpDir, 'gen-enums')
    const dmmf = makeDmmf(
      [],
      [
        {
          name: 'Role',
          values: [{ name: 'USER', dbName: null }, { name: 'ADMIN', dbName: null }],
        },
      ],
    )

    await generate(makeOptions(outputDir, dmmf))

    const content = await fs.promises.readFile(path.join(outputDir, 'rest-client.ts'), 'utf-8')
    expect(content).toContain('export enum Role {')
    expect(content).toContain("USER = 'USER',")
    expect(content).toContain("ADMIN = 'ADMIN',")
  })
})

